// 添加schema验证
fastify.get('/iterations/:id', {
  schema: { params: iterationParamsSchema }
}, async (request, reply) => {
  const { id } = request.params as { id: number };
  // id已经过验证，保证是正整数
  const iteration = iterationService.getDetail(id);
  // ...
});
```

**优先级**: ⚠️ **P2 - 中优先级**

