### Step 2: 创建认证中间件 (1小时)

创建文件: `src/dashboard/middleware/auth.middleware.ts`

```typescript
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import { FastifyRequest, FastifyReply } from 'fastify';

export interface AuthenticatedRequest extends FastifyRequest {
  user?: {
    id: string;
    username: string;
    role: 'admin' | 'viewer' | 'operator';
  };
}

export async function authenticateToken(
  request: AuthenticatedRequest,
  reply: FastifyReply
) {
  const authHeader = request.headers.authorization;

  if (!authHeader?.startsWith('Bearer ')) {
    return reply.code(401).send({
      success: false,
      error: { message: 'Bearer token required', code: 'UNAUTHORIZED' }
    });
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET || 'dev-secret') as any;
    request.user = decoded;
  } catch (error: any) {
    return reply.code(403).send({
      success: false,
      error: { 
        message: error.name === 'TokenExpiredError' ? 'Token expired' : 'Invalid token',
        code: 'FORBIDDEN' 
      }
    });
  }
}

export function requireRole(...allowedRoles: string[]) {
  return async (request: AuthenticatedRequest, reply: FastifyReply) => {
    if (!request.user) {
      return reply.code(401).send({
        success: false,
        error: { message: 'Authentication required', code: 'UNAUTHORIZED' }
      });
    }

    if (!allowedRoles.includes(request.user.role)) {
      return reply.code(403).send({
        success: false,
        error: { 
          message: `Role '${request.user.role}' not allowed. Required: ${allowedRoles.join(', ')}`,
          code: 'INSUFFICIENT_PERMISSIONS' 
        }
      });
    }
  };
}

// 简单的用户管理（生产环境应使用数据库）
const USERS = [
  {
    id: '1',
    username: 'admin',
    passwordHash: bcrypt.hashSync('admin123', 10), // 仅用于演示
    role: 'admin' as const
  }
];

export async function login(username: string, password: string) {
  const user = USERS.find(u => u.username === username);

  if (!user || !bcrypt.compareSync(password, user.passwordHash)) {
    throw new Error('Invalid credentials');
  }

  const token = jwt.sign(
    { id: user.id, username: user.username, role: user.role },
    process.env.JWT_SECRET || 'dev-secret',
    { expiresIn: '24h' }
  );

  return { token, user: { id: user.id, username: user.username, role: user.role } };
}
```

